import * as Yup from "yup";
import Select from "react-select";
import { toast } from "react-toastify";
import { useSelector } from "react-redux";
import "react-phone-input-2/lib/style.css";
import PhoneInput from "react-phone-input-2";
import { Country, State } from "country-state-city";
import { yupResolver } from "@hookform/resolvers/yup";
import { useForm, Controller } from "react-hook-form";
import React, { Fragment, useState, useEffect } from "react";
import { NavLink, useNavigate, useSearchParams } from "react-router-dom";
import { Col, Card, CardHeader, CardBody, Form, FormGroup, Label, Row, Input } from "reactstrap";

import Typeahead from "../../../CommonElements/TypeAhead";
import { Btn, H3, Breadcrumbs } from "../../../AbstractElements";
import HandleApiError from "../../Common/ErrorImport/ErrorImport";
import Transparentspinner from "../../Common/Loader/Transparentspinner";
import { getClientUrlDataToken, postClientUrlWithToken } from "../../../Utils/restUtils";
import { getArea, getAreaRole, getCustomers, getCustomersRole, getitemSelect, getitemSelectRole, getUsers, getUsersRole, showEnquiry, showEnquiryRole, storeEnquiry, storeEnquiryRole, updateEnquiry, updateEnquiryRole } from "../../../CommonUrl";
import {
    Address, Email,
    MobileNo, Save,
    Name,
    City,
    Cancel,
    newEnquiry,
    Company,
    Orgenization,
    Area,
    Notes,
    Product,
    AssignedTo,
    editEnquiry,
    existingCustomer,
    CustomerType,
    newCustomer,
    SourceToolTip
} from "../../../Constant";
import CustomTooltip from "../../Common/CommonTooltip/CustomTooltip";
import tooltip from "../../../assets/images/Icons/tooltip.svg"
import AreaAddModal from "../../Settings/Area/AreaAddModal";



const schema = Yup.object().shape({
    customerType: Yup.string().required('Customer Type is required'),
    source: Yup.mixed().required('Source is required'),
    customer: Yup.mixed().nullable().when("customerType",
        {
            is: "existing",
            then: (schema) =>
                schema?.required('Customer is required')
            , otherwise: (schema) =>
                schema.nullable()
        }
    ),
    name: Yup.string().nullable().when("customerType",
        {
            is: "new",
            then: (schema) =>
                schema?.required('Customer name is required')
                    .min(3, 'Customer name must be at least 3 characters')
                    .max(50, 'Customer name cannot exceed 50 characters')
                    .matches(
                        /^[A-Za-z ]+$/,
                        'Customer name should contain only letters and spaces'
                    )
            , otherwise: (schema) =>
                schema.nullable()
        }
    ),
    mobileNo: Yup.string().nullable().when("customerType",
        {
            is: "new",
            then: (schema) => (
                schema?.required('Phone number is required')
                    .min(6, 'Phone number must be at least 6 digits')
                    .max(15, 'Phone number cannot exceed 15 digits')
            )
            , otherwise: (schema) =>
                schema.nullable()
        }
    )

});

const AddEnquiries = () => {
    const { register, handleSubmit, control, getValues, watch, formState: { errors }, setValue } = useForm({
        resolver: yupResolver(schema),
        defaultValues: {
            customerType: "new"
        }

    });
    const authState = useSelector((state) => state.auth);
    const [productOption, setProductOption] = useState([]);
    const [areaOption, setAreaOption] = useState([]);
    const [userOption, setuserOption] = useState([]);
    const [loading, setLoading] = useState(false);
    const [selectedState, setSelectedState] = useState(null);
    const [selectedCountry, setselectedCountry] = useState(null);
    const [areaName, SetAreaName] = useState('')
    const [productName, SetProductName] = useState('')
    const [customerType, setCustomerType] = useState('new')
    const [customerOption, setCustomerOption] = useState()
    const [areaModal, setAreaModal] = useState(false)

    const [searchParams] = useSearchParams();

    const enquiryID = searchParams.get("id");


    const options = [
        { value: "website", label: "Website" },
        { value: "walk_in", label: "Walk In" },
        { value: "call", label: "Call" },
        { value: "referral", label: "Referral" },
        { value: "whatsapp", label: "Whatsapp" },
        { value: "other", label: "Other" },

    ];

    const customerTypeOption = [
        { value: "new", label: "New Customer" },
        { value: "existing", label: "Existing  Customer" }
    ]
    const navigate = useNavigate();


    //area option
    const areaData = async () => {
        let data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getArea : getAreaRole);
        if (data.status === true) {
            setAreaOption(
                data.data.map((item) => ({
                    value: item.id,
                    label: item.name,
                }))
            );
        }
        else if (data.status >= 400 && data.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (data.status >= 500 && data.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);

        }
    };

    //product option
    const itemcategory = async () => {
        const item_api = await getClientUrlDataToken(
            authState.apiUrl,
            authState.userRole === 1 ? getitemSelect : getitemSelectRole
        );
        if (item_api.status === true) {
            const data = item_api.data;
            const itemslist = data.map((items) => ({
                value: items.id,
                label: items.name,


            }));
            setProductOption(itemslist);
        } else {
            HandleApiError(data.status);
        }
    };

    //staff option
    const userData = async () => {
        const data = await getClientUrlDataToken(
            authState.apiUrl,
            authState.userRole === 1 ? getUsers : getUsersRole
        )
        if (data.status === true) {
            const option = data.data?.map((item) => ({
                label: item?.user_name,
                value: item?.user_id,
            }));
            setuserOption(option);
        }
    };

    //submit form
    const onSubmit = async (data) => {

        const countryCode = data?.countryCode;
        const phoneNumber = data?.mobileNo;

        setLoading(true);
        const mobile = phoneNumber?.slice(countryCode?.length) || "";
        const postRequest = {
            name: data.name,
            phone: mobile,
            country_code: data?.countryCode,
            email: data.email,
            address: data.address,
            source: data.source?.value,
            product_id: data.product?.value,
            ...(!enquiryID && { status: 'new' }),
            notes: data.notes,
            assigned_to: data.assign?.value,
            country: selectedCountry?.name,
            state: selectedState?.name,
            city: data.city,
            area_id: data.areaName?.value,
            customer_id: data?.customer?.value,
            company: data?.company,
            ...(enquiryID && { enquiry_id: enquiryID }),

        };


        setLoading(true);
        let addCustomerResponse
        if (enquiryID) {
            addCustomerResponse = await postClientUrlWithToken(
                authState.apiUrl, authState.userRole === 1 ? updateEnquiry : updateEnquiryRole, postRequest
            );

        }
        else {
            addCustomerResponse = await postClientUrlWithToken(
                authState.apiUrl, authState.userRole === 1 ? storeEnquiry : storeEnquiryRole, postRequest
            );
        }

        if (addCustomerResponse.status === 200) {
            if (addCustomerResponse.data.status === true) {
                navigate(`${process.env.PUBLIC_URL}/lead-manage/enquiry`);
                toast.success(addCustomerResponse.data.message);
            } else {
                toast.error(addCustomerResponse.data.message);
                setLoading(false);
            }
        } else if (addCustomerResponse.status >= 400 && addCustomerResponse.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (addCustomerResponse.status >= 500 && addCustomerResponse.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        } else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }

        setLoading(false);
    };

    //fetch enquiry details
    const handleFetEnquiryDetails = async () => {
        setLoading(true);
        const response = await getClientUrlDataToken(
            authState.apiUrl,
            authState.userRole === 1
                ? showEnquiry + `?enquiry_id=${enquiryID}`
                : showEnquiryRole + `?enquiry_id=${enquiryID}`
        );
        if (response.status === true) {
            const responseData = response.data.data[0]; // your API response object

            setValue('name', responseData?.name || '');
            setValue(
                'mobileNo',
                `+${responseData?.country_code}${responseData?.phone}`
            ), setValue('email', responseData?.email || '');
            setValue('countryCode', responseData?.country_code || '');
            setValue('company', responseData?.company || '');
            setValue('address', responseData?.address || '');
            setValue('area_name', responseData?.area_name || '');
            setValue('city', responseData?.city || '');
            setValue('state', responseData?.state || '');
            if (responseData.customer_exist === true) {
                setCustomerType('existing')
                setValue('customerType', "existing")

                const customer = await getClientUrlDataToken(
                    authState.apiUrl,
                    authState.userRole === 1 ? getCustomers : getCustomersRole
                );

                const curentCustomer = customer?.data?.find(
                    (item) => String(item.mobile) === String(responseData?.phone)
                );


                setValue(
                    "customer",
                    { label: curentCustomer?.name, value: curentCustomer?.id } || null
                );


            }
            else {
                setCustomerType('new')
                setValue('customerType', "new")
            }

            if (responseData?.country) {
                setselectedCountry({ name: responseData?.country })
            }
            if (responseData?.state) {
                setSelectedState({ name: responseData?.state })
            }
            if (responseData?.area_name) {
                SetAreaName(responseData?.area_name)
            }

            if (responseData?.source) {

                const currentSource = options?.find((item) => item?.value === responseData?.source)
                setValue('source', currentSource || '');
            }

            setValue('status', responseData?.status || '');
            setValue('notes', responseData?.notes || '');
            if (responseData?.assigned_user_name) {
                setValue('assign', { label: responseData?.assigned_user_name, value: responseData?.user_id } || '');

            }

            if (responseData?.product_name) {
                SetProductName(responseData?.product_name);

            }

        } else if (
            response.status >= 400 &&
            response.status <= 405
        ) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (
            response.status >= 500 &&
            response.status <= 505
        ) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        } else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }

        setLoading(false);

    }
    const oncCustomerTypeChange = (value) => {
        setCustomerType(value)
        setValue('customerType', value)
        setValue('mobileNo', '')
        setValue('email', '')
        setValue('name', '')
        setValue('customer', '')

    }


    const customerData = async () => {
        const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getCustomers : getCustomersRole);
        if (data.status === true) {
            const options = data.data.map((item) => ({
                value: item.id,
                searchFields: `${item.name} ${item.area_name} ${item.mobile} ${item.address}`,
                label: item.name,
            }));
            setCustomerOption(options);
        } else if (data.status >= 400 && data.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (data.status >= 500 && data.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        } else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
    };

    useEffect(() => {
        areaData();
        itemcategory()
        userData()
        customerData()
        if (enquiryID) {
            handleFetEnquiryDetails()
        }
    }, []);

    useEffect(() => {
        if (enquiryID) {
            if (areaName) {
                const areaData = areaOption?.find((item) => (item?.label === areaName))
                setValue('areaName', areaData)
            }
            if (productName) {
                const product = productOption?.find((item) => (item?.label === productName))
                setValue('product', product)
            }
        }
    }, [areaName, productName])
    return (
        <Fragment>
            {loading && <Transparentspinner />}

            <Breadcrumbs mainTitle={enquiryID ? editEnquiry : newEnquiry} parent="Enquiry" title={enquiryID ? editEnquiry : newEnquiry} />
            <Card>

                <CardBody>
                    <Form
                        className="needs-validation"
                        noValidate
                        onSubmit={handleSubmit(onSubmit)}
                    >
                        <Row className="g-3 pt-3">

                            <Col md="6">
                                <Label className="form-label" for="custmerType">
                                    {CustomerType}
                                    <span className="requireStar">*</span>
                                </Label>
                                <select name="" value={customerType} className="form-select" onChange={(e) => { oncCustomerTypeChange(e.target.value) }} id="">
                                    {
                                        customerTypeOption?.map((item) => (
                                            <option value={item?.value}>{item?.label}</option>
                                        ))

                                    }

                                </select>
                                {/* <Controller
                                    name="customerType"
                                    defaultValue={null}
                                    control={control}
                                    render={({ field }) => (
                                        <Typeahead
                                            options={customerTypeOption}
                                            onChange={(value) => {
                                                // field.onChange(value)
                                                oncCustomerTypeChange(value?.value)
                                            }}
                                            value={field.value}
                                        />
                                    )}
                                /> */}

                                {/* <div>
                                    <input
                                        type="radio"
                                        name="customerType"
                                        value="existing"
                                        className="form-radio"
                                        checked={customerType === "existing"}
                                        onChange={(e) => oncCustomerTypeChange(e.target.value)}
                                    />
                                    <Label className="ms-2">{existingCustomer}</Label>
                                </div>

                                <div>
                                    <input
                                        type="radio"
                                        name="customerType"
                                        value="new"
                                        className="form-radio"
                                        checked={customerType === "new"}
                                        onChange={(e) => oncCustomerTypeChange(e.target.value)}
                                    />
                                    <Label className="ms-2">{newCustomer}</Label>
                                </div> */}


                            </Col>
                            {
                                customerType === 'new' ?
                                    <>
                                        <Col md="6">
                                            <Label className="form-label" for="name">
                                                {Name}
                                                <span className="requireStar">*</span>
                                            </Label>
                                            <input
                                                className="form-control"
                                                id="name"
                                                type="text"
                                                placeholder="name"
                                                {...register("name", { required: true })}
                                            />
                                            <p className="text-danger">{errors.name?.message}</p>

                                        </Col>
                                        <Col md="6">
                                            <Label className="form-label" >
                                                {MobileNo} <span className="requireStar">*</span>
                                            </Label>
                                            <Controller
                                                name="mobileNo"
                                                control={control}
                                                defaultValue=""
                                                render={({ field }) => (
                                                    <PhoneInput
                                                        {...field}
                                                        country={"in"}
                                                        enableSearch={true}
                                                        onChange={(value, country) => {
                                                            setValue("countryCode", country.dialCode);
                                                            field.onChange(value);
                                                        }}
                                                        inputStyle={{
                                                            width: "100%",
                                                            height: "46px",
                                                            padding: "10px",
                                                            paddingLeft: "50px",
                                                            fontSize: "16px",
                                                            borderRadius: "8px",
                                                            borderColor: "rgba(83, 70, 134, 0.1019607843)",
                                                        }}
                                                        searchClass="none"
                                                    />
                                                )}
                                            />
                                            <span className="text-danger">
                                                {errors.mobileNo?.message}
                                            </span>
                                        </Col>
                                        <Col md="6">
                                            <Label className="form-label" for="email">
                                                {Email}
                                            </Label>
                                            <input
                                                className="form-control"
                                                id="email"
                                                type="email"
                                                placeholder="Email"
                                                {...register("email")}
                                            />
                                            <p className="text-danger">{errors.email?.message}</p>
                                        </Col>
                                    </>
                                    :

                                    <>
                                        <Col md='6'>
                                            <Label>{existingCustomer}<span className="requireStar">*</span></Label>
                                            <Controller
                                                name="customer"
                                                defaultValue={null}
                                                control={control}
                                                render={({ field }) => (
                                                    <Typeahead
                                                        options={customerOption}
                                                        onChange={(value) => {
                                                            field.onChange(value);
                                                        }}
                                                        value={field.value}
                                                    />
                                                )}
                                            />
                                        </Col>
                                    </>

                            }
                            <Col md='6'>
                                <Label className="form-label" style={{ display: "flex", alignItems: "center" }}>
                                    Source
                                    <span className="requireStar">*</span>
                                    <span id="sourceTip"><img src={tooltip} style={{ width: "18px", marginLeft: "4px", cursor: "pointer" }} /></span>
                                </Label>
                                <CustomTooltip id="sourceTip" text={SourceToolTip} />
                                <Controller
                                    name="source"
                                    control={control}
                                    render={({ field }) => (
                                        <Typeahead
                                            options={options}
                                            onChange={(value) => {
                                                field.onChange(value);

                                            }}
                                            value={field.value}
                                        />
                                    )}
                                />
                                <span className="text-danger">
                                    {errors.source?.message}
                                </span>

                            </Col>
                            <Col md="6">
                                <Label className="form-label" for="lastaname">
                                    {Company} / {Orgenization}
                                </Label>
                                <input
                                    className="form-control"
                                    id="company"
                                    type="text"
                                    name="company"
                                    placeholder="Company/Organization"
                                    {...register("company")}
                                />

                            </Col>

                            <Col md="6">
                                <Label htmlFor='country' className="col-form-label">Country </Label>
                                <Select
                                    options={Country.getAllCountries()}
                                    getOptionLabel={(options) => options["name"]}
                                    getOptionValue={(options) => options["name"]}
                                    value={selectedCountry}
                                    onChange={(item) => {
                                        setselectedCountry(item);

                                    }}
                                    styles={{
                                        control: (baseStyles, state) => ({
                                            ...baseStyles,
                                            height: 45,
                                        }),
                                        menu: (baseStyles) => ({
                                            ...baseStyles,
                                            zIndex: 1000,
                                        }),
                                    }}
                                    theme={(theme) => ({
                                        ...theme,
                                        colors: {
                                            ...theme.colors,
                                            primary25: 'rgba(83, 70, 134, 0.474)',
                                            primary: '#534686',
                                            primary50: 'rgba(83, 70, 134, 0.3)'
                                        },
                                    })}
                                />
                            </Col>
                            <Col md='6'>
                                <Label htmlFor='state' className="col-form-label">State</Label>
                                <Select
                                    options={State?.getStatesOfCountry(selectedCountry?.isoCode)}
                                    getOptionLabel={(options) => options["name"]}
                                    getOptionValue={(options) => options["name"]}
                                    value={selectedState}
                                    onChange={(item) => {
                                        setSelectedState(item);
                                    }}
                                    styles={{
                                        control: (baseStyles, state) => ({
                                            ...baseStyles,
                                            height: 45,
                                        }),
                                        menu: (baseStyles) => ({
                                            ...baseStyles,
                                            zIndex: 1000,
                                        }),
                                    }}
                                    theme={(theme) => ({
                                        ...theme,
                                        colors: {
                                            ...theme.colors,
                                            primary25: 'rgba(83, 70, 134, 0.474)',
                                            primary: '#534686',
                                            primary50: 'rgba(83, 70, 134, 0.3)'
                                        },
                                    })}
                                />

                            </Col>
                            <Col md="6">
                                <Label className="form-label" >
                                    {City}
                                </Label>
                                <input
                                    className="form-control"
                                    id="city"
                                    type="text"
                                    name="city"
                                    placeholder="City"
                                    {...register("city")}

                                />
                            </Col>
                            <Col md="6">
                                <Row>
                                    <Label className="form-label" >
                                        {Area}
                                    </Label>
                                    <Col xs='10'>
                                        <Controller
                                            name="areaName"
                                            control={control}
                                            render={({ field }) => (
                                                <Typeahead
                                                    options={areaOption}
                                                    onChange={(value) => {
                                                        field.onChange(value);

                                                    }}
                                                    value={field.value}
                                                />
                                            )}
                                        />
                                    </Col>
                                    <Col xs="2" className="d-flex align-items-stretch p-0 ">
                                        <button
                                            onClick={() => setAreaModal(true)}
                                            type="button"
                                            className="btn btn-primary "
                                        >
                                            +
                                        </button>
                                    </Col>

                                </Row>
                            </Col>

                            <Col md='6'>
                                <Label className="form-label">{Address}</Label>
                                <textarea className="form-control"
                                    name="address"
                                    placeholder="Address"
                                    {...register("address")}


                                />

                            </Col>

                            <Col md='6'>
                                <Label className="form-label" >
                                    {AssignedTo}

                                </Label>
                                <Controller
                                    name="assign"
                                    control={control}
                                    render={({ field }) => (
                                        <Typeahead
                                            options={userOption}
                                            onChange={(value) => {
                                                field.onChange(value);

                                            }}
                                            value={field.value}
                                        />
                                    )}
                                />

                            </Col>
                            <Col md='6'>
                                <Label className="form-label" >
                                    {Product}

                                </Label>
                                <Controller
                                    name="product"
                                    control={control}
                                    render={({ field }) => (
                                        <Typeahead
                                            options={productOption}
                                            onChange={(value) => {
                                                field.onChange(value);

                                            }}
                                            value={field.value}
                                        />
                                    )}
                                />

                            </Col>
                            <Col md='12'>
                                <Label className="form-label" >
                                    {Notes}

                                </Label>
                                <textarea className="form-control"
                                    name="notes"
                                    placeholder="Notes"
                                    {...register("notes")}
                                />

                            </Col>

                        </Row>

                        <FormGroup></FormGroup>
                        <Btn attrBtn={{ color: "primary" }} type="submit"> {Save} </Btn>
                        <NavLink className={'btn btn-outline-primary  mx-2 '} to={'/lead-manage/enquiry'} > {Cancel} </NavLink>
                    </Form>
                    <AreaAddModal
                        area={areaData}
                        setValue={setValue}
                        handleModal={() => {
                            setAreaModal(!areaModal);
                        }}
                        modal={areaModal}
                    />
                </CardBody>
            </Card>
        </Fragment>
    );
};
export default AddEnquiries;
